import { jsx, jsxs } from 'react/jsx-runtime';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import { Icon } from '../Icon/Icon.js';
import { Typography } from '../Typography/Typography.js';

const renderChildren = (children, isCollapsed, onClick) => {
    const childrenLength = children?.length;
    const separator = jsx(Icon, { iconName: Icons.NavArrowRight, className: "dsb-breadcrumbs__separator-icon", size: "small" });
    if (!isCollapsed || childrenLength < 3 || !childrenLength) {
        return (Array.isArray(children) ? children : [children])?.reduce((res, link, i) => {
            res.push(jsxs("li", { className: "dsb-breadcrumbs__item", itemProp: "itemListElement", children: [link, jsx("meta", { itemProp: "position", content: String(i + 1) })] }, i));
            if (i < childrenLength - 1) {
                res.push(jsx("li", { className: "dsb-breadcrumbs__separator", children: separator }, `${i}${separator}`));
            }
            return res;
        }, []);
    }
    return [
        jsxs("li", { className: "dsb-breadcrumbs__item", itemProp: "itemListElement", children: [children?.[0], jsx("meta", { itemProp: "position", content: '1' })] }, 'a'),
        jsx("li", { className: "dsb-breadcrumbs__separator", children: separator }, 'b'),
        jsx(Typography, { className: "dsb-breadcrumbs__dots", variant: 'body3', onClick: onClick, children: "..." }, 'c'),
        jsx("li", { className: "dsb-breadcrumbs__separator", children: separator }, 'd'),
        jsxs("li", { className: "dsb-breadcrumbs__item", children: [children?.[childrenLength - 1], jsx("meta", { itemProp: "position", content: String(childrenLength) })] }, 'e'),
    ];
};

export { renderChildren };
